import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"花衣吹笛手","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/2.社交类/花衣吹笛手.md","filePath":"4.资源分区/1.血统与训练/2.社交类/花衣吹笛手.md"}'),s={name:"4.资源分区/1.血统与训练/2.社交类/花衣吹笛手.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"花衣吹笛手",tabindex:"-1"},[p("花衣吹笛手 "),r("a",{class:"header-anchor",href:"#花衣吹笛手","aria-label":'Permalink to "花衣吹笛手"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),n('<h1 id="花衣吹笛手-1" tabindex="-1">花衣吹笛手 <a class="header-anchor" href="#花衣吹笛手-1" aria-label="Permalink to &quot;花衣吹笛手&quot;">​</a></h1><p>【花衣吹笛手】<br> 神话本质<br> D+600<br> 前置要求：花衣魔笛手（1）或拥有笛类攻击方式/技艺/武器<br> 花衣的吹笛手，总是在演奏着<br> 他的笛声带着魔力，他的演奏奏响回音<br> 究竟是魔笛赋予了他魔力<br> 还是他赋予了笛声意义？<br> 【吹笛】<br> 笛声要如何才能传递到他人那里？<br> 那就演奏吧，奏响的声音将逐渐扩大<br> 直到那带走灾难之音成为灾难<br> 直到合上双耳也无法阻止演奏<br> 你将获得一个基于【魔笛】的特殊能量池【魔音】，构成为操控+沉着，需要在获得时绑定一个笛类攻击方式/技艺/武器，绑定后的事物将被称呼为【魔笛】，此后不可更改。<br> 魔音的恢复方式：<br> 1、短休息时进行一个操控+沉着属性检定，恢复成功数点能量<br> 2、长休息结束后恢复至满值<br> 同时，你获得魔音的基础用法——【奏响魔笛】<br> 奏响魔笛：使用一个自由动作并消耗2点【魔音】，悠扬之乐曲响起，该回合，你基于绑定事物的攻击将转变为对以自身为中心5米圆形范围内所有目标造成伤害。</p><p>【回音】：你的每一次演奏，都是为了下一次，下下次的演奏。每场影片中，当你在战斗中奏响魔笛并赢得胜利，你将在影片结束后使得笛类攻击射程增加1米。</p><p>【带走灾难之笛手】<br> C+1200<br> 哈默林的街上，奏响的是怎样的音色呢？<br> 在那些穿着华丽的大人们的耳中，它又是怎样奏响的呢？<br> 当乐声响起，鼠群便将跟他而去，最终，淹没在哈默林的河流中。<br> 【哈默林】：哈默林，哈默林，灾难来临，你灾害遍地的街上，又奏响的是谁的声音？<br> 此时，奏响魔笛获得第二个使用方式<br> 若你保留有足够转化为一个标准动作的AP，那么你可以额外使用一个移动动作并再次消耗6点【魔音】强化接下来的一次攻击，并调用这个标准动作以绑定的【魔笛】发动攻击，攻击可以附带技艺，但需遵守AP规则，若不足或无法转化，则无法发动【哈默林】<br> 随后，哈默林的街道将重现于此——<br> 此时，奏响魔笛进行的范围攻击将不再消耗【魔音】，持续一场景。</p><p>攻击后你可以立刻进行一次移动（前提是你每次攻击前都消耗一个移动动作进行强化），所有受到笛声影响的事物将以意志豁免对抗攻击伤害出目，失败则会向你指定的方向移动差值/米，这是一个类拖拽效果，同时视为等同该训练等级的心灵来源负面效果。</p><p>哈默林的吹笛手会将灾害导向何处？<br> 哈默林的河水会吞没一切<br> 在此次移动后，被移动的目标还需要使用反射豁免对抗上述提及攻击伤害出目，失败则因为沉入【哈默林】虚假的河水中而陷入C级别、影响心灵来源的【窒息】状态，这是一个C级心灵来源的负面效果。</p><p>【哈默林的河流】：你并非真正的哈默林花衣吹笛手，但，人们对他的传颂使得你可以使哈默林的河流以概念重现。<br> 若有灾害在哈默林的河水中死亡，会令灾害更加深陷其中——每场影片一次，若哈默林的河水中有事物死亡，并且那场战斗胜利，你在攻击陷入【窒息】状态的单位时，额外造成1点伤害。</p><p>【哈默林的花衣魔笛手】<br> B+2400<br> 哈默林的花衣魔笛手<br> 他的笛声比什么都要深邃的鸣响着<br> 当笛声第二次奏响，最后受到吸引的，究竟是鼠群，还是稚嫩的幼群？<br> 【第一次的笛音】：最初的笛声时，倾听者是疯狂的鼠群，为它们奏响的，是通往死亡的乐曲，它们将跟随你的笛声、你的方向，逐步走向死亡。<br> 最后<br> 由沉静的河流带走一切，唯有笛声依旧回荡<br> 当【奏响魔笛】时，所有人都将知晓，这究竟是怎样的乐章，处于【奏响魔笛】效果时，获得以下效果。<br> 【魔笛】攻击检定中具有的加骰提升1级（至多8加骰）<br> 【魔笛】的攻击将使目标需以意志豁免对抗伤害出目，失败则在意志豁免上获得【劣化2】，这是一个B级心灵来源的负面效果，持续一轮。</p><p>【第二次的回响】：最后的笛声时，倾听者是什么都未曾知晓的幼群，以及无知的背信之人们，轻柔的，欢快的，将幼群们带向未知的乐园的，是最后奏响的安魂曲。<br> 当奏响【哈默林】时，只有目睹一切，铭记哈默林的惨剧，人才能继续成长。<br> 你在【魔笛】攻击检定上获得【9加骰】，在【哈默林】中跟随笛声的‘孩子’，将走向山的方向，当山体裂开的时候，孩子们将一拥而入，那边是孩子们的乐园，是传说中梦中的天国，随后再不回来——本应该如此，这意味着你在【魔笛】攻击命中后，目标需要使用意志豁免对抗伤害出目，失败则被放逐一轮，这是一个B级的命运来源的放逐效果。</p><p>【花衣魔笛手】<br> 前置：【花衣魔笛手】（1）<br> 购买该专长2，3级的价格改为10/20XP，需逐级支付。<br> 通用专长<br> 2级<br> 花衣魔笛手，他是一个持有神器魔笛的少年，他能令害虫起舞，他能使害兽止步，他能让鼠患淹没在河水当中<br> 魔笛是他力量的来源，他的一切技艺，都是为了更好的施展魔笛。<br> 当你吹响魔笛时，你的攻击方式【笛声】也将因此获得额外的加成，你在使用笛类武器进行攻击时，若武器伤害不足6点，则提升至6点。<br> 当然，在你手持魔笛时，你的笛声将能免疫C级的沉默效果，如一开始所说，魔笛，是一个拥有魔力的笛子，它的声音总是无法被阻挡的。<br> 而你外来者的本质比起之前，或许已不再那么明显。<br> 彩衣现在将能转而为你提供D级的命运来源背景身份，但还是会有人一眼就能得知，你并非那个国家，或者那座城市的人。不过，他们大概会知道，你是一个普普通通的，其他地方的过来的人。当然，此时你也将拥有对应的身份证件与足够短期生存的金钱，只是你终究不是这里的人，如果仔细查询你的身份，将发现你并未过往的经历。<br> 3级<br> 魔笛啊魔笛，我将吹奏你，你的乐曲令人着迷，哪怕就只是一刻的声音——它现在将能展现出，它部分的，真正的威力。<br> 少年吹奏起了长笛，你可以在非战斗轮的场景下花费15分钟进行一次【操控+表达+魔笛】的演奏检定，可直接听见笛声（即你对他们的听觉感知方式而言具有模糊定位）的单位需要使用意志豁免，DC为成功数，失败在一日内被你吹奏的笛声所吸引。</p><p>在单位受影响期间，你如果在距离它们不超过传奇操控*1公里的范围内吹奏起魔笛，你的笛声将同时在受到影响的人耳畔响起，这是一个D级别的【信息共享】效果，当然这个共享后的笛声并不会令其受到你吹奏产生的额外影响，仅会令他们试图往你的方向汇集，以聆听你的乐曲，如果他们抵达你身边的路途不算困难，且不会因此遭受什么损失或者前往从未去过的地方，这是C级别、影响心灵来源的【思维控制】效果；理所当然的，在受影响单位本身看来这不是一个恶意效果（但可以正常被免疫），受到影响的目标也不会认为自己因此做出的举动有什么奇怪的地方，并将听到的笛声合理化。</p><p>彩衣啊彩衣，我是一个来自远方的客人，他们祝福我的到来，他们更加认识，一个并非我的自己。<br> 彩衣给予你的背景身份将提升至C级，你是从其其他城市来的客人，但你从来遇不到和你一个城市的人。不过，你的身份撑得过查验，你的记忆也让你知道，他确有其人，你拥有可以查验的过往经历，你拥有这个身份可以拥有的一切，房屋、交通工具、金钱——当然，你不会拥有额外的人际关系，这只是普通人级别的身份。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
